const now = new Date();
const month = now.toISOString().slice(0, 7);
const daysInMonth = new Date(now.getFullYear(), now.getMonth() + 1, 0).getDate();
const dayOfMonth = now.getDate();
const daysLeft = daysInMonth - dayOfMonth;

return [{
  json: {
    bridgeUrl:        'http://actual-bridge:3788',
    telegramChatId:   'REPLACE_WITH_YOUR_TELEGRAM_CHAT_ID',
    currentMonth: month,
    daysLeft,
    dayOfMonth,
    weekNumber: Math.ceil(dayOfMonth / 7),
  }
}];

const monthData = $input.item.json;
const config = $('Config').item.json;
const groups = monthData.data?.categoryGroups || [];

// Skip these groups from the briefing
const skipGroups = ['Income'];
// Skip these individual categories
const skipCategories = ['Starting Balances', 'CC Carrying Balance'];

let totalBudgeted = 0;
let totalSpent = 0;
let overspent = [];
let warnings = [];
let budgetSections = [];

for (const group of groups) {
  if (group.hidden || skipGroups.includes(group.name)) continue;
  const cats = [];
  for (const cat of (group.categories || [])) {
    if (cat.hidden || skipCategories.includes(cat.name)) continue;
    const budgeted = (cat.budgeted || 0) / 100;
    const spent = Math.abs((cat.spent || 0) / 100);
    const balance = (cat.balance || 0) / 100;
    const pct = budgeted > 0 ? Math.round((spent / budgeted) * 100) : 0;
    totalBudgeted += budgeted;
    totalSpent += spent;
    if (balance < 0) overspent.push({ name: cat.name, over: Math.abs(balance) });
    else if (pct > 80 && config.daysLeft > 5) warnings.push({ name: cat.name, pct, balance });
    if (budgeted > 0 || spent > 0) cats.push({ name: cat.name, budgeted, spent, balance, pct });
  }
  if (cats.length > 0) budgetSections.push({ groupName: group.name, categories: cats });
}

return [{ json: { ...config, budgetSections, totalBudgeted, totalSpent, totalRemaining: totalBudgeted - totalSpent, overspent, warnings } }];

const d = $input.item.json;
let summary = '';
for (const s of d.budgetSections) {
  summary += `\n${s.groupName}:\n`;
  for (const c of s.categories) {
    summary += `  ${c.name}: $${c.spent.toFixed(0)} of $${c.budgeted.toFixed(0)} (${c.pct}% used, $${c.balance.toFixed(0)} left)\n`;
  }
}

const prompt = `You are a personal financial assistant. It's Sunday evening in Detroit, MI. Give a concise weekly budget briefing.

Context:
- Week ${d.weekNumber} of the month, ${d.daysLeft} days remaining
- Total budgeted: $${d.totalBudgeted.toFixed(0)}, spent: $${d.totalSpent.toFixed(0)}, remaining: $${d.totalRemaining.toFixed(0)}
- Overspent categories: ${d.overspent.length > 0 ? d.overspent.map(c => c.name + ' ($' + c.over.toFixed(0) + ' over)').join(', ') : 'None'}
- Warning (>80% used): ${d.warnings.length > 0 ? d.warnings.map(c => c.name + ' ' + c.pct + '%').join(', ') : 'None'}

Budget detail:${summary}

Write a brief (under 200 words), direct, friendly briefing. Lead with the overall picture, flag anything urgent, end with one practical suggestion for the week. Plain text only, no markdown.`;

return [{ json: { ...d, prompt } }];

const res = $input.item.json;
const config = $('Build Prompt').item.json;
const summary = res.content?.[0]?.text || 'Unable to generate summary.';
const date = new Date().toLocaleDateString('en-US', { weekday: 'long', month: 'long', day: 'numeric' });

let msg = 'WEEKLY FINANCIAL BRIEFING - ' + date + '\n\n';
msg += summary;
if (config.overspent.length > 0) {
  msg += '\n\nOVERSPENT: ' + config.overspent.map(c => c.name + ' ($' + c.over.toFixed(0) + ' over)').join(', ');
}
msg += '\n\n--- Quick Stats ---';
msg += '\nSpent: $' + config.totalSpent.toFixed(0) + ' / $' + config.totalBudgeted.toFixed(0) + ' budgeted';
msg += '\nRemaining: $' + config.totalRemaining.toFixed(0) + ' | ' + config.daysLeft + ' days left';

return [{ json: { ...config, telegramMessage: msg } }];
